b'import pytest\nfrom cli import convert\n\n\ndef test_convert_same_unit():\n    assert convert(100, "celsius", "celsius") == 100\n\n\ndef test_celsius_to_fahrenheit():\n    assert convert(0, "celsius", "fahrenheit") == pytest.approx(32)\n\n\ndef test_fahrenheit_to_celsius():\n    assert convert(32, "fahrenheit", "celsius") == pytest.approx(0)\n\n\ndef test_celsius_to_kelvin():\n    assert convert(0, "celsius", "kelvin") == pytest.approx(273.15)\n\n\ndef test_kelvin_to_celsius():\n    assert convert(273.15, "kelvin", "celsius") == pytest.approx(0.0)\n\n\ndef test_kelvin_to_fahrenheit():\n    assert convert(273.15, "kelvin", "fahrenheit") == pytest.approx(32.0)\n\n\ndef test_fahrenheit_to_kelvin():\n    assert convert(32, "fahrenheit", "kelvin") == pytest.approx(273.15)\n\n\ndef test_invalid_conversion():\n    with pytest.raises(ValueError):\n        convert(100, "celsius", "invalid")\n\n\ndef test_negative_values():\n    assert convert(-40, "celsius", "fahrenheit") == pytest.approx(-40)\n    assert convert(-273.15, "celsius", "kelvin") == pytest.approx(0)\n    assert convert(-40, "fahrenheit", "celsius") == pytest.approx(-40)\n\n\ndef test_edge_cases():\n    assert convert(100, "celsius", "kelvin") == pytest.approx(373.15)\n    assert convert(212, "fahrenheit", "kelvin") == pytest.approx(373.15)\n    assert convert(0, "kelvin", "fahrenheit") == pytest.approx(-459.67)'